const inputData = items[0].json;

// Usamos el objeto "query" directamente, ya que es un objeto.
let parsedData = (inputData.query && typeof inputData.query === "object") ? inputData.query : {};

// Función para corregir el email (si hace falta insertar "@" antes del dominio)
function fixEmail(email) {
    if (email.includes("@")) {
        return email;
    }
    const domains = ["gmail.com", "hotmail.com", "yahoo.com", "outlook.com", "live.com", "icloud.com"];
    for (const domain of domains) {
        const pos = email.indexOf(domain);
        if (pos !== -1) {
            return email.substring(0, pos) + "@" + email.substring(pos);
        }
    }
    // Si no se encuentra un dominio conocido, inserta "@" a la mitad
    const mid = Math.floor(email.length / 2);
    return email.substring(0, mid) + "@" + email.substring(mid);
}

// Función para convertir la fecha a formato YYYY-MM-DD.
// Soporta varios formatos:
// - Si el delimitador es "-" se asume año-mes-día (YY-MM-DD o YYYY-MM-DD)
// - Si el delimitador es "/" se asume día/mes/año (DD/MM/YY o DD/MM/YYYY)
// En los casos en que el año venga en dos dígitos se forzará a 2025.
function parseDate(dateStr) {
    if (!dateStr) return "2025-01-01";
    dateStr = dateStr.trim();

    // Detectamos el delimitador usado
    let delimiter = dateStr.includes("-") ? "-" : "/";
    const parts = dateStr.split(delimiter);
    if (parts.length !== 3) return "2025-01-01";

    let day, month, year;

    if (delimiter === "-") {
        // Formato año-mes-día
        if (parts[0].length === 4) {
            // Ej: 2025-02-20
            year = parts[0];
        } else {
            // Para YY, forzamos el año a 2025
            year = "2025";
        }
        month = parts[1].padStart(2, "0");
        day = parts[2].padStart(2, "0");
    } else {
        // Delimitador "/", se asume normalmente DD/MM/YY o DD/MM/YYYY
        // Pero si el primer componente tiene 4 dígitos, se asume año-mes-día.
        if (parts[0].length === 4) {
            // Ej: 2025/02/20
            year = parts[0];
            month = parts[1].padStart(2, "0");
            day = parts[2].padStart(2, "0");
        } else {
            // Se asume DD/MM/YY
            day = parts[0].padStart(2, "0");
            month = parts[1].padStart(2, "0");
            // Si el año es de 4 dígitos se respeta, sino se fuerza a 2025
            year = parts[2].length === 4 ? parts[2] : "2025";
        }
    }
    return `${year}-${month}-${day}`;
}

// Función para ajustar la hora
// timeStr debe venir en formato "HH:MM" o "HH:MM:SS"
function adjustTime(timeStr, adjustment) {
    if (!timeStr) return "00:00:00";
    // Tomamos los primeros 5 caracteres para obtener "HH:MM"
    const cleanTime = timeStr.substring(0, 5);
    const parts = cleanTime.split(":");
    let hours = parseInt(parts[0], 10);
    let minutes = parseInt(parts[1], 10);
    let totalMinutes = hours * 60 + minutes + adjustment;
    // Normalizamos para que el resultado esté entre 0 y 24*60 (considerando ciclo de 24 hs)
    totalMinutes = ((totalMinutes % (24 * 60)) + (24 * 60)) % (24 * 60);
    const newHours = Math.floor(totalMinutes / 60);
    const newMinutes = totalMinutes % 60;
    return `${newHours.toString().padStart(2, "0")}:${newMinutes.toString().padStart(2, "0")}:00`;
}

// Extraemos los valores necesarios
const nombre = parsedData.nombre ? parsedData.nombre.trim() : "Nombre no encontrado";
const email = parsedData.email ? fixEmail(parsedData.email.trim()) : "email@noencontrado.com";
const dia = parsedData["Dia elegido"] ? parseDate(parsedData["Dia elegido"].trim()) : "2025-01-01";
const horarioBase = parsedData["horario elegido"] ? parsedData["horario elegido"].trim() : "00:00";

// Calcular horarios:
// horario_inicio: 120 minutos *antes* del horario elegido.
const horarioInicio = adjustTime(horarioBase, -120);
// horario_fin: 60 minutos *después* del horario_inicio.
const horarioFin = adjustTime(horarioInicio.substring(0, 5), 60);

return [{
  json: {
    "disponibilidad": {
      "dia": dia,
      "horario_inicio": horarioInicio,
      "horario_fin": horarioFin,
      "email": email,
      "nombre": nombre
    }
  }
}];

